class Solution:
    def numPairsDivisibleBy60(self, time: List[int]) -> int:
        counts = [0] * 60
        total = 0
        for t in time:
            r = t % 60
            complement = (60 - r) % 60
            total += counts[complement]
            counts[r] += 1
        return total

